WITH
VOLUME AS
(
SELECT
  DISTINCT(DD.STORE_ID),
  COUNT(DISTINCT(DD.DELIVERY_ID)) AS VOLUME,
  SUM(DD.SUBTOTAL/100) AS GOV
  
FROM DIMENSION_LOCAL_DELIVERIES DD
LEFT JOIN EDW.MERCHANT.DIMENSION_STORE DS ON DS.STORE_ID = DD.STORE_ID

WHERE 1=1
AND DS.COUNTRY_ID IN (2)
AND DS.IS_RESTAURANT = TRUE
AND DD.ACTIVE_DATE BETWEEN CURRENT_DATE()-30 AND CURRENT_DATE()-1
AND DD.IS_FROM_STORE_TO_US = FALSE
AND DD.IS_TEST = FALSE
AND DD.ACTIVE_DATE IS NOT NULL
GROUP BY ALL
)
,
managed_stores as 
(
Select 
  distinct(ma.business_id),
  ma.segment,
  --fr.region_id,
  --fr.region_name,
  ma.account_owner
  --ds.business_name,
  --ma.start_date

from static.mx_managed_accounts MA 
--janisng.prelim_mx_managed_accounts MA
left join static.spm_region_mapping sm on sm.account_owner = ma.account_owner
left join public.fact_region fr on sm.region_id = fr.region_id
left join edw.merchant.dimension_store ds on ma.business_id = ds.business_id

where 1=1
--AND fr.REGION_NAME IN ('Canada')
AND 
(
ds.business_name NOT LIKE ('%Inactive%')
or
ds.business_name NOT LIKE ('%DNU%')
or
ds.business_name NOT LIKE ('%Do Not Use%')
)

and ds.is_partner = 1
and ds.is_active = 1
and ds.is_test = false
--order by 1,3
)
,
biz_with_cohorts_and_AOs AS
(
SELECT DISTINCT 
    bgl.BUSINESS_ID
    , bgl.business_name
    , bgl.business_group_id
    , bgl.group_name as business_group_name
    , ent.Enterprise_book_bg_Type as enterprise_cohort 
    , ent.account_owner
    , ent.team_manager as team_lead
    , ent.Holding_Group_name as  HOLDING_GROUP
    , case when ent.RX = True then 'RX' else 'NV' end as RX_NV
    , BS.business_vertical_id
    , BS.serving_experience
    , BS.nv_vertical_name
    , BS.nv_business_line
    , BS.nv_business_sub_type
    , BS.nv_org
    , bs.is_active
    , bs.is_test 
    , ctry.shortname as Country

FROM EDW.MERCHANT.DIMENSION_BUSINESS_GROUP_LINK bgl 
JOIN EDW.MERCHANT.DIMENSION_BUSINESS BS ON bgl.BUSINESS_ID = BS.BUSINESS_ID
JOIN proddb.static.ENTERPRISE_BUSINESS_BOOK ent on ent.business_group_id = bgl.business_group_id
JOIN geo_intelligence.public.maindb_country CTRY ON ENT.WALK_COUNTRY_ID = CTRY.ID
)
,
stores_under_ao as 
(
SELECT 
ent.account_owner,
count(distinct ds.store_id) as num_stores_under_ao

FROM EDW.MERCHANT.DIMENSION_BUSINESS_GROUP_LINK bgl 
JOIN EDW.MERCHANT.DIMENSION_BUSINESS BS ON bgl.BUSINESS_ID = BS.BUSINESS_ID
JOIN proddb.static.ENTERPRISE_BUSINESS_BOOK ent on ent.business_group_id = bgl.business_group_id
join edw.merchant.dimension_store ds on ds.business_id = bs.business_id

where 1=1
and ds.is_test = 0
and ds.is_active = 1
group by ALL
)
,
providers_by_store as 
(
select 
    store.PROVIDER_TYPE,
    store.BUSINESS_ID,
    store.BUSINESS_NAME,
    setup.integrated_special_hours_via_special_hours,
    setup.integrated_special_hours_via_regular_hours,
    store.STORE_ID

from DOORDASH_POINTOFSALE.PUBLIC.MAINDB_STORE store
left join PRODDB.STATIC.STORE_AVAILABILITY as setup on setup.provider_id = store.provider_type
where 1=1
and regexp_like(store.PROVIDER_TYPE, '.*dummy.*') = false and regexp_like(store.PROVIDER_TYPE, '.*test.*') = false
)
,
main_info_at_biz_level AS
(
SELECT
   BIZ.business_id
  -- Exclude system/generic users: Holding User, Self-Serve Integration User, Enterprise Holding User, Mulesoft Integration User, Formstack Integration User, etc.
  ,MODE(IFF(BIZ.account_owner ILIKE '% User%', NULL, BIZ.account_owner)) AS main_AO
  ,MODE(BIZ.business_vertical_id) AS main_business_vertical_id
  ,MODE(BIZ.enterprise_cohort) AS main_ent_cohort
  ,MODE(BIZ.holding_group) AS main_ent_holding_group

FROM biz_with_cohorts_and_AOs BIZ
GROUP BY 1
)
,
stores_with_special_hrs AS
(
    SELECT DISTINCT
         store_id
        ,TRY_TO_DATE(date) date
    FROM
    (
        SELECT
             store_id
            ,TRY_TO_DATE(date) date
        FROM EDW.MERCHANT.DIMENSION_MENU_SPECIAL_HOURS MSH
        WHERE
            date IN
            (
                '2026-04-05' -- Easter 2026
                ,'2026-05-25' -- Memorial Day (MD) 2026  
                ,'2026-07-04' -- Independence Day (ID) 2026 
                ,'2026-09-07' -- Labor Day (LD) 2026 
                ,'2026-11-25' -- Thanksgiving Eve (TGE) 2026
                ,'2026-11-26' -- Thanksgiving Day (TGD) 2026
                ,'2026-11-27' -- Black Friday (BF) 2026
                ,'2026-12-24' -- Christmas Eve (XME) 2026
                ,'2026-12-25' -- Christmas Day (XMD) 2026
                ,'2026-12-31' -- New Year's Eve (NYE) 2026
                ,'2027-01-01' -- New Year's Day (NYD) 2027
            )
        UNION ALL

        SELECT
             TRY_TO_NUMERIC(store_menu_id) AS store_id
            ,TRY_TO_DATE(date)
        FROM menu.public.cassandra_store_level_hour_exception SSH
        WHERE
            date IN
            (
                 '2026-02-16' -- Family Day (FD) 2026
                ,'2026-04-03' -- Good Friday (GF) 2026
                ,'2026-04-05' -- Easter Sunday (ES) 2026
                ,'2026-04-06' -- Easter Monday (EM) 2026
                ,'2026-05-18' -- Victoria Day (VD) 2026
                ,'2026-07-01' -- Canada Day (CD) 2026
                ,'2026-09-07' -- Labour Day (LD) 2026
                ,'2026-09-30' -- National Day for Truth and Reconciliation (TRC) 2026
                ,'2026-10-12' -- Thanksgiving Day (TGD) 2026
                ,'2026-11-11' -- Remembrance Day (RD) 2026
                ,'2026-12-24' -- Christmas Eve (XME) 2026
                ,'2026-12-25' -- Christmas Day (XMD) 2026
                ,'2026-12-31' -- New Years Eve (NYE) 2026
                ,'2027-01-01' -- New Years Day (NYD) 2027
            )
            AND NOT NVL(is_deleted, FALSE)
            AND description IS DISTINCT FROM 'DoorDash Adjusted Hours' -- Special hours set by DoorDash as part of Programmatic Hours, not by the Mx.
    )
)

,
holidays AS
(
   SELECT date, holiday_ts
    FROM
    ( VALUES
 ('2026-02-16', '2026-04-03'::date) -- Family Day (FD) 2026
,('2026-04-03', '2026-04-03'::date) -- Good Friday (GF) 2026
,('2026-04-05', '2026-04-05'::date) -- Easter Sunday (ES) 2026
,('2026-04-06', '2026-04-06'::date) -- Easter Monday (EM) 2026
,('2026-05-18', '2026-05-18'::date) -- Victoria Day (VD) 2026
,('2026-07-01', '2026-07-01'::date) -- Canada Day (CD) 2026
,('2026-09-07', '2026-09-07'::date) -- Labour Day (LD) 2026
,('2026-09-30', '2026-09-30'::date) -- National Day for Truth and Reconciliation (TRC) 2026
,('2026-10-12', '2026-10-12'::date) -- Thanksgiving Day (TGD) 2026
,('2026-11-11', '2026-11-11'::date) -- Remembrance Day (RD) 2026
,('2026-12-24', '2026-12-24'::date) -- Christmas Eve (XME) 2026
,('2026-12-25', '2026-12-25'::date) -- Christmas Day (XMD) 2026
,('2026-12-31', '2026-12-31'::date) -- New Years Eve (NYE) 2026
,('2027-01-01', '2027-01-01'::date) -- New Years Day (NYD) 2027
    ) AS T (date, holiday_ts)
)

, store_count as 
(
  select
  business_id,
  count(distinct store_id) as num_stores
  from edw.merchant.dimension_store
  where is_active = 1
  and is_test = 0
  group by 1
)

SELECT distinct
   DS.business_name
  ,DS.business_id
  -- ,MIB.main_AO AS account_owner
  ,CASE 
    WHEN DS.BUSINESS_ID IN (SELECT BUSINESS_ID FROM managed_stores) THEN OAM.ACCOUNT_OWNER
    ELSE MIB.main_AO
  END AS ACCOUNT_OWNER
  ,MIB.main_ent_cohort AS enterprise_cohort
  ,DS.store_id
  ,pos_store.provider_type
  ,NVL(pos_store.integrated_special_hours_via_special_hours, false) integrated_special_hours_via_special_hours
  ,NVL(pos_store.integrated_special_hours_via_regular_hours, false) integrated_special_hours_via_regular_hours
  ,DS.country_id
  ,DECODE(
     DS.country_id
    ,1, 'United States'
    ,2, 'Canada'
    ,5, 'Australia'
    ,404, 'Japan'
    ,470, 'Germany'
    ,503, 'New Zeland'
    ,'Others'
  ) AS country_name
  ,H.date
  ,DECODE(
       H.date
      ,'2026-02-16', 'Family Day (FD) 2026'
      ,'2026-04-03', 'Good Friday (GF) 2026'
      ,'2026-04-05', 'Easter Sunday (ES) 2026'
      ,'2026-04-06', 'Easter Monday (EM) 2026'
      ,'2026-05-18', 'Victoria Day (VD) 2026'
      ,'2026-07-01', 'Canada Day (CD) 2026'
      ,'2026-09-07', 'Labour Day (LD) 2026'
      ,'2026-09-30', 'Truth and Reconciliation Day (TRC) 2026'
      ,'2026-10-12', 'Thanksgiving Day (TGD) 2026'
      ,'2026-11-11', 'Remembrance Day (RD) 2026'
      ,'2026-12-24', 'Christmas Eve (XME) 2026'
      ,'2026-12-25', 'Christmas Day (XMD) 2026'
      ,'2026-12-31', 'NY Eve (NYE) 2026'
      ,'2027-01-01', 'NY Day (NYD) 2027'
      ,'Exclude'
  ) AS holiday
  ,IFF(SH.store_id IS NOT NULL,1,0) AS has_special_hours
  ,IFF(SH.store_id IS NOT NULL,'Hours Submitted','Hours Not Submitted') AS has_special_hours_text
  ,COUNT(DISTINCT(DS.STORE_ID)) OVER (PARTITION BY DS.BUSINESS_NAME) AS num_stores
  ,COUNT(DISTINCT(DS.STORE_ID)) OVER (PARTITION BY 
  (CASE 
    WHEN DS.BUSINESS_ID IN (SELECT BUSINESS_ID FROM managed_stores) THEN OAM.ACCOUNT_OWNER
    ELSE MIB.main_AO
  END)
  ) AS num_stores_under_ao
  ,
