END AS RISK_COHORT
,CASE WHEN DS.BUSINESS_ID IN (SELECT BUSINESS_ID FROM managed_stores) THEN 'OAM' ELSE DS.MANAGEMENT_TYPE END AS MANAGEMENT_TYPE
,VOLUME AS L30D_VOLUME
,GOV AS L30D_GOV
,CASE WHEN RT.RISK_TIER IS NULL THEN 'RISK_TIER_2' ELSE RT.RISK_TIER END AS UPDATED_RISK_TIER

FROM edw.merchant.dimension_store  DS
CROSS JOIN holidays H
LEFT JOIN stores_with_special_hrs SH
  ON SH.store_id = DS.store_id
  AND SH.date = H.date
LEFT JOIN main_info_at_biz_level MIB
  ON MIB.business_id = DS.business_id
LEFT JOIN providers_by_store pos_store 
  ON pos_store.store_id = DS.STORE_ID
LEFT JOIN edw.merchant.dimension_business main_biz
    on main_biz.UNIFIED_PRIMARY_BUSINESS_ID = DS.BUSINESS_ID
LEFT JOIN edw.merchant.DIMENSION_BUSINESS_GROUP_LINK bgr
    on ds.business_id = bgr.BUSINESS_ID
left join store_count sc on ds.business_id = sc.business_id
left join stores_under_ao sua on sua.account_owner = MIB.main_AO
LEFT JOIN managed_stores OAM ON DS.BUSINESS_ID = OAM.BUSINESS_ID
LEFT JOIN VOLUME V ON V.STORE_ID = DS.STORE_ID
LEFT JOIN NEILRATONEL.RISK_TIERS_VICTORIA_DAY_2026 RT ON RT.STORE_ID = DS.STORE_ID
 
WHERE
  NOT DS.is_test
  AND (DS.IS_ACTIVE or DS.IS_ACTIVE is null)
  AND main_biz.is_active 
  AND (main_biz.IS_TEST = false or main_biz.IS_TEST is null)
  AND (main_biz.business_vertical_id is null or main_biz.business_vertical_id = 0) -- Rx only
  and ds.country_id in (2)
  and ds.is_restaurant = true
  --and integrated_special_hours_via_regular_hours = false
  order by 3,2,5,11,14